import { Component, OnInit } from '@angular/core';
import { BookService } from '../../services/book.service';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-return-book',
  templateUrl: './return-book.component.html',
  styleUrls: ['./return-book.component.css']
})
export class ReturnBookComponent implements OnInit {
  userIssuedBooks: any[] = [];
  isLoading: boolean = false;
  successMessage: string = '';
  errorMessage: string = '';

  currentUser: any = null;

  constructor(private bookService: BookService, private authService: AuthService) {}

  ngOnInit(): void {
    this.currentUser = this.authService.getCurrentUser();
    this.loadUserIssuedBooks();
  }

  loadUserIssuedBooks(): void {
    if (this.currentUser) {
      this.userIssuedBooks = this.bookService.getIssuedBooksByUser(this.currentUser.id)
        .filter((book: any) => book.status === 'issued');
    }
  }

  returnBook(issuedBookId: string): void {
    if (!this.currentUser) {
      this.errorMessage = 'Please login to return books';
      return;
    }

    if (confirm('Are you sure you want to return this book?')) {
      this.isLoading = true;
      this.errorMessage = '';
      this.successMessage = '';

      const result = this.bookService.returnBook(issuedBookId);

      if (result.success) {
        this.successMessage = result.message;
        this.loadUserIssuedBooks();
      } else {
        this.errorMessage = result.message;
      }

      this.isLoading = false;

      setTimeout(() => {
        this.clearMessages();
      }, 5000);
    }
  }

  clearMessages(): void {
    this.successMessage = '';
    this.errorMessage = '';
  }

  getBookTitle(bookId: string): string {
    const book = this.bookService.getBookById(bookId);
    return book ? book.title : 'Unknown Book';
  }

  getBookAuthor(bookId: string): string {
    const book = this.bookService.getBookById(bookId);
    return book ? book.author : 'Unknown Author';
  }

  getDueStatus(dueDate: Date | string): string {
    const due = new Date(dueDate);
    const today = new Date();
    const daysLeft = Math.ceil((due.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

    if (daysLeft < 0) {
      return `Overdue by ${Math.abs(daysLeft)} days`;
    } else if (daysLeft === 0) {
      return 'Due today';
    } else if (daysLeft === 1) {
      return 'Due tomorrow';
    } else {
      return `${daysLeft} days left`;
    }
  }

  isOverdue(dueDate: Date | string): boolean {
    return new Date(dueDate) < new Date();
  }

  calculateFine(issuedBook: any): number {
    const dueDate = new Date(issuedBook.dueDate);
    const today = new Date();
    const daysOverdue = Math.max(0, Math.floor((today.getTime() - dueDate.getTime()) / (1000 * 60 * 60 * 24)));
    return daysOverdue * 5; // ₹5 per day
  }

  formatDate(date: Date | string): string {
    const d = new Date(date);
    return d.toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: 'short', 
      day: 'numeric' 
    });
  }

  hasOverdueBooks(): boolean {
    return this.userIssuedBooks.some((book: any) => this.isOverdue(book.dueDate));
  }

  getTotalFine(): number {
    return this.userIssuedBooks.reduce((total: number, book: any) => 
      total + (this.isOverdue(book.dueDate) ? this.calculateFine(book) : 0), 0
    );
  }

  returnAllBooks(): void {
    if (this.userIssuedBooks.length === 0) {
      this.errorMessage = 'No books to return';
      return;
    }

    if (confirm(`Are you sure you want to return all ${this.userIssuedBooks.length} books?`)) {
      let successCount = 0;
      let totalFine = 0;

      this.userIssuedBooks.forEach((issuedBook: any) => {
        const result = this.bookService.returnBook(issuedBook.id);
        if (result.success) {
          successCount++;
          totalFine += result.fine || 0;
        }
      });

      if (successCount > 0) {
        this.successMessage = `Successfully returned ${successCount} book(s). Total fine: ₹${totalFine}`;
        this.loadUserIssuedBooks();
      } else {
        this.errorMessage = 'Failed to return books';
      }

      setTimeout(() => {
        this.clearMessages();
      }, 5000);
    }
  }
}
<div class="return-book-container">
  <div class="page-header">
    <h1>📤 Return Book</h1>
    <p>Return borrowed books and calculate fines</p>
  </div>

  <!-- Messages -->
  <div class="message-container">
    <div class="error-message" *ngIf="errorMessage">
      {{ errorMessage }}
      <button class="close-btn" (click)="clearMessages()">×</button>
    </div>

    <div class="success-message" *ngIf="successMessage">
      {{ successMessage }}
      <button class="close-btn" (click)="clearMessages()">×</button>
    </div>
  </div>

  <div class="return-section">
    <div class="section-card">
      <div class="section-header">
        <h2>My Issued Books ({{ userIssuedBooks.length }})</h2>
        <button 
          class="return-all-btn" 
          (click)="returnAllBooks()"
          [disabled]="userIssuedBooks.length === 0 || isLoading"
          *ngIf="userIssuedBooks.length > 1"
        >
          📦 Return All
        </button>
      </div>

      <div *ngIf="userIssuedBooks.length === 0" class="empty-state">
        <div class="empty-icon">📚</div>
        <h3>No books to return</h3>
        <p>You haven't issued any books or have already returned all of them.</p>
      </div>

      <div class="issued-books-grid" *ngIf="userIssuedBooks.length > 0">
        <div 
          *ngFor="let issuedBook of userIssuedBooks" 
          class="issued-book-card"
        >
          <div class="book-header">
            <h3 class="book-title">{{ getBookTitle(issuedBook.bookId) }}</h3>
            <span 
              class="due-status" 
              [class.overdue]="isOverdue(issuedBook.dueDate)"
            >
              {{ getDueStatus(issuedBook.dueDate) }}
            </span>
          </div>

          <div class="book-details">
            <div class="detail-row">
              <span class="label">Author:</span>
              <span class="value">{{ getBookAuthor(issuedBook.bookId) }}</span>
            </div>

            <div class="detail-row">
              <span class="label">Issue Date:</span>
              <span class="value">{{ formatDate(issuedBook.issueDate) }}</span>
            </div>

            <div class="detail-row">
              <span class="label">Due Date:</span>
              <span class="value due-date" [class.overdue]="isOverdue(issuedBook.dueDate)">
                {{ formatDate(issuedBook.dueDate) }}
              </span>
            </div>

            <div class="detail-row" *ngIf="isOverdue(issuedBook.dueDate)">
              <span class="label">Fine:</span>
              <span class="value fine-amount">₹{{ calculateFine(issuedBook) }}</span>
            </div>
          </div>

          <div class="book-actions">
            <button 
              class="return-btn" 
              (click)="returnBook(issuedBook.id)"
              [disabled]="isLoading"
            >
              <span *ngIf="!isLoading">📤 Return Book</span>
              <span *ngIf="isLoading">Processing...</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  </div>

  <!-- Fine Information -->
  <div class="fine-info-card" *ngIf="hasOverdueBooks()">
    <h3>💰 Fine Information</h3>
    <div class="fine-details">
      <p><strong>Fine Rate:</strong> Rs5 per day after due date</p>
      <p><strong>Calculation:</strong> Days overdue × Rs5 = Total fine</p>
      <div class="total-fine">
        <strong>Total Fine for Overdue Books:</strong> 
        <span class="fine-amount">
          Rs{{ getTotalFine() }}
        </span>
      </div>
    </div>
  </div>

  <!-- Instructions -->
  <div class="instructions-card">
    <h3>📋 Return Instructions</h3>
    <ul>
      <li>Click "Return Book" to return individual books</li>
      <li>Use "Return All" to return all issued books at once</li>
      <li>Fines are automatically calculated for overdue books</li>
      <li>Books must be returned in good condition</li>
      <li>Contact library staff for any issues with returns</li>
    </ul>
  </div>
</div>
